package test.rice;

import main.rice.PrimeFactorizer;
import org.junit.jupiter.api.Test;

import static org.junit.jupiter.api.Assertions.assertArrayEquals;
import static org.junit.jupiter.api.Assertions.assertNull;

public class PrimeFactorizerAgentTest {
    private static final PrimeFactorizer smallFactorizer = new PrimeFactorizer(100);
    private static final PrimeFactorizer largeFactorizer = new PrimeFactorizer(50000000);

    @Test
    void factorizeOneReturnsNull() {
        assertNull(smallFactorizer.computePrimeFactorization(1));
    }

    @Test
    void factorizePrimeReturnsSingleElementArray() {
        assertArrayEquals(new int[]{97}, smallFactorizer.computePrimeFactorization(97));
    }

    @Test
    void factorizeCompositeReturnsRepeatedFactors() {
        assertArrayEquals(new int[]{2, 2, 3}, smallFactorizer.computePrimeFactorization(12));
    }

    @Test
    void factorizeMaximumValueWhenComposite() {
        assertArrayEquals(new int[]{2, 2, 5, 5}, smallFactorizer.computePrimeFactorization(100));
    }

    @Test
    void factorizeLargePrimeNearUpperBound() {
        assertArrayEquals(new int[]{32452843}, largeFactorizer.computePrimeFactorization(32452843));
    }

    @Test
    void factorizeLargeComposite() {
        assertArrayEquals(
                new int[]{2, 2, 2, 2, 2, 2, 2, 5, 5, 5, 5, 5, 5, 5, 5},
                largeFactorizer.computePrimeFactorization(50000000)
        );
    }
}

package main.rice;

import java.util.ArrayList;
import java.util.List;

/**
 * This class implements a relatively simple algorithm for computing (and printing) the
 * prime factors of a number.  At initialization, a list of primes is computed. Given a
 * number, this list is used to efficiently compute the prime factors of that number.
 */
public class PrimeFactorizer {
    private final int maxNumToFactorize;
    private final int[] primes;

    public PrimeFactorizer(int maxNumToFactorize) {
        this.maxNumToFactorize = maxNumToFactorize;
        this.primes = computePrimesUpTo(maxNumToFactorize);
    }

    public int[] computePrimeFactorization(int numToFactorize) {
        if (numToFactorize <= 1 || numToFactorize > maxNumToFactorize) {
            return null;
        }

        List<Integer> factors = new ArrayList<>();
        int remainder = numToFactorize;

        for (int prime : primes) {
            if ((long) prime * prime > remainder) {
                break;
            }

            while (remainder % prime == 0) {
                factors.add(prime);
                remainder /= prime;
            }
        }

        if (remainder > 1) {
            factors.add(remainder);
        }

        int[] result = new int[factors.size()];
        for (int i = 0; i < factors.size(); i++) {
            result[i] = factors.get(i);
        }
        return result;
    }

    private static int[] computePrimesUpTo(int max) {
        if (max < 2) {
            return new int[0];
        }

        boolean[] isComposite = new boolean[max + 1];
        List<Integer> primeList = new ArrayList<>();

        for (int candidate = 2; candidate <= max; candidate++) {
            if (!isComposite[candidate]) {
                primeList.add(candidate);
                if ((long) candidate * candidate <= max) {
                    for (int multiple = candidate * candidate; multiple <= max; multiple += candidate) {
                        isComposite[multiple] = true;
                    }
                }
            }
        }

        int[] result = new int[primeList.size()];
        for (int i = 0; i < primeList.size(); i++) {
            result[i] = primeList.get(i);
        }
        return result;
    }
}

